class _Lit:
    def __init__(self, ch):
        self.ch = ch

    def match(self, text, pos, cont):
        if pos < len(text) and text[pos] == self.ch:
            return cont(pos + 1)
        return False


class _AnyChar:
    def match(self, text, pos, cont):
        if pos < len(text):
            return cont(pos + 1)
        return False


class _CharClass:
    def __init__(self, negate, ranges):
        self.negate = negate
        self.ranges = ranges

    def _test(self, ch):
        in_range = any(lo <= ch <= hi for lo, hi in self.ranges)
        return in_range != self.negate

    def match(self, text, pos, cont):
        if pos < len(text) and self._test(text[pos]):
            return cont(pos + 1)
        return False


class _Concat:
    def __init__(self, parts):
        self.parts = parts

    def match(self, text, pos, cont):
        return self._match_from(0, text, pos, cont)

    def _match_from(self, idx, text, pos, cont):
        if idx == len(self.parts):
            return cont(pos)
        return self.parts[idx].match(
            text, pos, lambda p: self._match_from(idx + 1, text, p, cont)
        )


class _Alt:
    def __init__(self, options):
        self.options = options

    def match(self, text, pos, cont):
        for opt in self.options:
            if opt.match(text, pos, cont):
                return True
        return False


class _Star:
    def __init__(self, sub):
        self.sub = sub

    def match(self, text, pos, cont):
        def helper(p):
            def k(p2):
                if p2 == p:
                    return cont(p2)
                return helper(p2)

            if self.sub.match(text, p, k):
                return True
            return cont(p)

        return helper(pos)


class _Plus:
    def __init__(self, sub):
        self.sub = sub

    def match(self, text, pos, cont):
        star = _Star(self.sub)
        return self.sub.match(text, pos, lambda p: star.match(text, p, cont))


class _Opt:
    def __init__(self, sub):
        self.sub = sub

    def match(self, text, pos, cont):
        if self.sub.match(text, pos, cont):
            return True
        return cont(pos)


def _parse_class(s, i):
    i += 1
    negate = False
    if i < len(s) and s[i] == "^":
        negate = True
        i += 1
    ranges = []
    while i < len(s) and s[i] != "]":
        c1 = s[i]
        if i + 2 < len(s) and s[i + 1] == "-" and s[i + 2] != "]":
            ranges.append((c1, s[i + 2]))
            i += 3
        else:
            ranges.append((c1, c1))
            i += 1
    i += 1
    return _CharClass(negate, ranges), i


def _parse_atom(s, i):
    c = s[i]
    if c == "(":
        i += 1
        node, i = _parse_expr(s, i)
        i += 1
        return node, i
    if c == "[":
        return _parse_class(s, i)
    if c == ".":
        return _AnyChar(), i + 1
    return _Lit(c), i + 1


def _parse_factor(s, i):
    atom, i = _parse_atom(s, i)
    if i < len(s) and s[i] in "*+?":
        q = s[i]
        i += 1
        if q == "*":
            atom = _Star(atom)
        elif q == "+":
            atom = _Plus(atom)
        else:
            atom = _Opt(atom)
    return atom, i


def _parse_term(s, i):
    factors = []
    while i < len(s) and s[i] not in "|)":
        factor, i = _parse_factor(s, i)
        factors.append(factor)
    if len(factors) == 1:
        return factors[0], i
    return _Concat(factors), i


def _parse_expr(s, i):
    term, i = _parse_term(s, i)
    terms = [term]
    while i < len(s) and s[i] == "|":
        i += 1
        term, i = _parse_term(s, i)
        terms.append(term)
    if len(terms) == 1:
        return terms[0], i
    return _Alt(terms), i


def match(pattern: str, text: str) -> bool:
    node, _ = _parse_expr(pattern, 0)

    def final_cont(pos):
        return pos == len(text)

    return node.match(text, 0, final_cont)
